use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;
use std::sync::mpsc::{channel, Receiver, Sender};

fn watch_directory(path: &Path, sender: Sender<PathBuf>) {
    loop {
        if let Ok(entries) = fs::read_dir(path) {
            for entry in entries {
                if let Ok(entry) = entry {
                    let path = entry.path();
                    if path.is_file() {
                        sender.send(path.clone()).unwrap();
                    }
                }
            }
        }
        thread::sleep(Duration::from_secs(1));
    }
}

fn process_files(receiver: Receiver<PathBuf>, dir_map: Arc<Mutex<HashMap<PathBuf, Vec<PathBuf>>>>) {
    while let Ok(path) = receiver.recv() {
        if let Some(extension) = path.extension().and_then(|s| s.to_str()) {
            let mut dir_map = dir_map.lock().unwrap();
            let entry = dir_map.entry(PathBuf::from(extension)).or_insert_with(Vec::new);
            if !entry.contains(&path) {
                entry.push(path.clone());
                let target_dir = path.parent().unwrap().join(extension);
                if !target_dir.exists() {
                    fs::create_dir(&target_dir).unwrap();
                }
                let target_path = target_dir.join(path.file_name().unwrap());
                fs::rename(&path, &target_path).unwrap();
            }
        }
    }
}

fn main() {
    let (sender, receiver) = channel();
    let dir_map = Arc::new(Mutex::new(HashMap::new()));
    let dir_map_clone = Arc::clone(&dir_map);

    let monitor_thread = thread::spawn(move || {
        watch_directory(Path::new("./watched_dir"), sender);
    });

    let process_thread = thread::spawn(move || {
        process_files(receiver, dir_map_clone);
    });

    monitor_thread.join().unwrap();
    process_thread.join().unwrap();
}

