            System.out.println("Usage: java CSVTool <input.csv> <output.csv> <config.properties>");
            return;
        }

        Path inputPath = Paths.get(args[0]);
        Path outputPath = Paths.get(args[1]);
        Path configPath = Paths.get(args[2]);

        if (Files.size(inputPath) > MAX_FILE_SIZE) {
            System.out.println("Error: File size exceeds 1 GB.");
            return;
        }

        Properties config = new Properties();
        try (InputStream configStream = Files.newInputStream(configPath)) {
            config.load(configStream);
        }

        List<String> columnOrder = Arrays.asList(config.getProperty("columnOrder", "").split(","));
        Set<String> uniqueRows = new HashSet<>();

        try (BufferedReader reader = Files.newBufferedReader(inputPath);
             BufferedWriter writer = Files.newBufferedWriter(outputPath)) {

            String header = reader.readLine();
            if (header == null) {
                System.out.println("Error: Empty CSV file.");
                return;
            }

            List<String> headers = Arrays.asList(header.split(","));
            List<Integer> reorderIndices = columnOrder.stream()
                    .map(headers::indexOf)
                    .collect(Collectors.toList());

            writer.write(String.join(",", columnOrder));
            writer.newLine();

            reader.lines()
                    .map((var line) -> line.split(","))
                    .filter((var values) -> values.length == headers.size())
                    .map((var values) -> {
                        List<String> reordered = reorderIndices.stream()
                                .map((var i) -> i >= 0 ? values[i] : "")
                                .collect(Collectors.toList());
                        return String.join(",", reordered);
                    })
                    .filter(uniqueRows::add) // Remove duplicates
                    .forEach((var line) -> {
                        try {
                            writer.write(line);
                            writer.newLine();
                        } catch (IOException e) {
                            e.printStackTrace();
                        }
                    });
        }

        System.out.println("CSV file processing complete.");
    }
}
