async fn handle_connection(mut stream: TcpStream) {
    let mut buffer = vec![0; 1024];

    if let Ok(_) = stream.read(&mut buffer).await {
        let request = String::from_utf8_lossy(&buffer);
        if request.starts_with("GET /") {
            let request_line: Vec<&str> = request.split_whitespace().collect();
            let path = if request_line.len() > 1 {
                request_line[1].trim_start_matches('/')
            } else {
                "index.html"
            };

            serve_file(&path, stream).await;
        }
    }
}

async fn serve_file(path: &str, mut stream: TcpStream) {
    let path = if path.is_empty() { "index.html" } else { path };
    let path = Path::new(path);

    if let Ok(mut file) = File::open(path).await {
        let mime_type = from_path(path).first_or_octet_stream();
        let response_header = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: {}\r\n\r\n",
            mime_type
        );
        let header = Arc::new(response_header.into_bytes());

        let _ = stream.write_all(&header).await;

        let mut file_buffer = vec![0; 8192];
        while let Ok(n) = file.read(&mut file_buffer).await {
            if n == 0 {
