import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.Executors;
import java.util.concurrent.ThreadPoolExecutor;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpServer;
import com.sun.net.httpserver.HttpHandler;
import com.sun.net.httpserver.HttpExchange;
import java.io.IOException;
import java.io.OutputStream;

public class MonitoringTool {

    private static OperatingSystemMXBean osBean;
    private static ThreadPoolExecutor executor;

    static class Metrics {
        long totalMemoryUsed;
        long memoryAvailable;
        double cpuUtilization;

        public Metrics(long totalMemoryUsed, long memoryAvailable, double cpuUtilization) {
            this.totalMemoryUsed = totalMemoryUsed;
            this.memoryAvailable = memoryAvailable;
            this.cpuUtilization = cpuUtilization;
        }
    }

    public static void main(String[] args) throws Exception {
        osBean = ManagementFactory.getPlatformMXBean(OperatingSystemMXBean.class);
        executor = (ThreadPoolExecutor) Executors.newFixedThreadPool(10);

        HttpServer server = HttpServer.create(new InetSocketAddress(8080), 0);
        server.createContext("/stats", new MonitoringHandler());
        server.setExecutor(executor);
        server.start();

        performHttpRequest();
    }

    static class MonitoringHandler implements HttpHandler {
        @Override
        public void handle(HttpExchange exchange) throws IOException {
            if ("GET".equals(exchange.getRequestMethod())) {
                Metrics metrics = getMetrics();
                ObjectMapper objectMapper = new ObjectMapper();
                String response = objectMapper.writeValueAsString(metrics);
                exchange.getResponseHeaders().set("Content-Type", "application/json");
                exchange.sendResponseHeaders(200, response.getBytes().length);
                try(OutputStream os = exchange.getResponseBody()) {
                    os.write(response.getBytes());
                }
            } else {
                exchange.sendResponseHeaders(405, -1); // Method Not Allowed
            }
        }
    }

    private static Metrics getMetrics() {
        long totalMemoryUsed = Runtime.getRuntime().totalMemory() - Runtime.getRuntime().freeMemory();
        long memoryAvailable = Runtime.getRuntime().maxMemory();
        double cpuUtilization = osBean.getSystemLoadAverage() / osBean.getAvailableProcessors() * 100;

        return new Metrics(totalMemoryUsed, memoryAvailable, cpuUtilization);
    }

    private static void performHttpRequest() throws Exception {
        HttpClient client = HttpClient.newBuilder().build();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(new URI("http://localhost:8080/stats"))
                .build();
        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        System.out.println(response.body());
    }
