        executor.submit(() -> {
            logger.info("Processing file: " + filePath);
            if (Files.isRegularFile(filePath) && (filePath.toString().endsWith(".jpg") || filePath.toString().endsWith(".jpeg") || filePath.toString().endsWith(".png"))) {
