                } catch (TesseractException e) {
                    logger.severe("Error during OCR: " + e.getMessage());
                } catch (IOException e) {
                    logger.severe("File writing error: " + e.getMessage());
                }
            } else {
                logger.info("Skipped non-image file: " + filePath);
            }
        });
    }
