async fn main() {
    dotenv().ok();

    let database_url = env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let migration_dir: PathBuf = env::var("MIGRATION_DIR")
        .expect("MIGRATION_DIR must be set")
