async fn run_migrations(pool: &PgPool, migration_dir: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let conn = pool.get()?;

    let mut migrations = fs::read_dir(migration_dir).await?;
    let mut migration_list = Vec::new();

    while let Some(entry) = migrations.next().await {
        let entry = entry?;
        if entry.file_name().to_string_lossy().ends_with(".sql") {
            migration_list.push(entry);
        }
