logging.basicConfig(filename='migration.log', level=logging.INFO)

def is_legacy_crypt_hash(hash_str):
    return hash_str.startswith(('$1$', '$2$', '$3$', '$4$', '$5$', '$6$'))

def hash_password(password, salt, iterations=100000, algorithm='sha256'):
    return hashlib.pbkdf2_hmac(algorithm, password.encode(), salt.encode(), iterations)

def migrate_password_hashes(directory):
    hash_count = 0
    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            with open(file_path, 'r') as f:
                lines = f.readlines()

            updated_lines = []
            for line in lines:
                password = line.strip()
                if is_legacy_crypt_hash(password):
                    salt = os.urandom(16).hex()
                    new_hash = hash_password(password, salt)
                    updated_lines.append(new_hash.hex() + '\n')
                    hash_count += 1
                else:
                    updated_lines.append(line)

            if len(updated_lines) > len(lines):  # Update if any hash is modified
                with open(file_path, 'w') as f:
                    f.writelines(updated_lines)

    logging.info(f'Upgraded {hash_count} password hashes')

if __name__ == '__main__':
